const ticket = $input.first().json;

// Extract ticket details from webhook payload
const customerEmail = ticket.body?.email || ticket.body?.from || 'unknown';
const subject = ticket.body?.subject || 'No subject';
const message = ticket.body?.message || ticket.body?.text || ticket.body?.body || '';
const businessId = ticket.body?.business_id || 'bayflow';

return [{
  json: {
    customerEmail,
    subject,
    message,
    businessId,
    receivedAt: new Date().toISOString(),
    prompt: `You are the Support Agent for ${businessId}. Your goal is to auto-resolve 70-80% of tickets. Be helpful, concise, and friendly.

Ticket from: ${customerEmail}
Subject: ${subject}
Message: ${message}

Respond with a JSON object (no markdown code blocks) containing:
{
  "can_resolve": true/false,
  "response_to_customer": "your response if can_resolve is true",
  "escalation_reason": "reason if can_resolve is false",
  "ticket_tag": "bug" | "feature-request" | "confusion" | "billing" | "how-to" | "other",
  "feature_request_summary": "if ticket_tag is feature-request, summarize what they want in one sentence, otherwise null",
  "severity": "low" | "medium" | "high"
}

You CAN resolve: password resets, how-to questions, billing inquiries, general product questions, onboarding help.
You CANNOT resolve: bugs requiring code changes, account-specific data issues, refund requests over $50, anything requiring access to production systems.

Always be empathetic. Use the customer's name if available. Keep responses under 200 words.`
  }
}];

const responseText = $json.text;
let parsed;
try {
  parsed = JSON.parse(responseText);
} catch (e) {
  // Try to extract JSON from response
  const match = responseText.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  } else {
    parsed = {
      can_resolve: false,
      escalation_reason: 'Failed to parse AI response',
      ticket_tag: 'other',
      severity: 'medium'
    };
  }
}

const ticket = $('Parse Ticket').first().json;

return [{
  json: {
    ...parsed,
    customerEmail: ticket.customerEmail,
    subject: ticket.subject,
    message: ticket.message,
    businessId: ticket.businessId,
    receivedAt: ticket.receivedAt,
    processedAt: new Date().toISOString()
  }
}];

// Get the ticket data from Process AI Response
const ticket = $('Process AI Response').first().json;

// Try to get existing log content and SHA from the GitHub read
const readResult = $input.first().json;
let existingContent = '';
let sha = null;
let fileExists = false;

// Check if the read succeeded (file exists)
if (readResult.content && !readResult.error) {
  // GitHub returns base64-encoded content
  if (readResult.encoding === 'base64') {
    existingContent = Buffer.from(readResult.content, 'base64').toString('utf-8');
  } else {
    existingContent = readResult.content;
  }
  sha = readResult.sha;
  fileExists = true;
}

// Format the new ticket entry
const now = new Date();
const dateStr = now.toISOString().split('T')[0];
const timeStr = now.toISOString().split('T')[1].split('.')[0];

let newEntry = `## Ticket - ${dateStr} ${timeStr}\n`;
newEntry += `**From:** ${ticket.customerEmail}\n`;
newEntry += `**Subject:** ${ticket.subject}\n`;
newEntry += `**Tag:** ${ticket.ticket_tag}\n`;
newEntry += `**Severity:** ${ticket.severity}\n`;
newEntry += `**Resolved:** ${ticket.can_resolve}\n`;

if (ticket.can_resolve) {
  newEntry += `**Response:** ${ticket.response_to_customer}\n`;
} else {
  newEntry += `**Escalation Reason:** ${ticket.escalation_reason}\n`;
}

if (ticket.feature_request_summary) {
  newEntry += `**Feature Request:** ${ticket.feature_request_summary}\n`;
}

newEntry += `\n---\n\n`;

// Build full content: header (if new file) + existing entries + new entry
let fullContent;
if (fileExists && existingContent.trim().length > 0) {
  fullContent = existingContent.trimEnd() + '\n\n' + newEntry;
} else {
  fullContent = `# Support Log\n\n` + newEntry;
}

return [{
  json: {
    fileContent: fullContent,
    sha: sha,
    fileExists: fileExists,
    businessId: ticket.businessId
  }
}];
